using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class ModelTests
{
    // --- Person.FullName tests (using Student since Person is abstract) ---

    [TestMethod]
    public void FullName_BothNamesSet_ReturnsLastNameCommaFirstName()
    {
        // Arrange
        var student = new Student { LastName = "Smith", FirstMidName = "John" };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual("Smith, John", result);
    }

    [TestMethod]
    [DataRow("Doe", "Jane", "Doe, Jane")]
    [DataRow("O'Brien", "Conan", "O'Brien, Conan")]
    [DataRow("De La Cruz", "Maria", "De La Cruz, Maria")]
    public void FullName_VariousNames_ReturnsExpectedFormat(string lastName, string firstMidName, string expected)
    {
        // Arrange
        var student = new Student { LastName = lastName, FirstMidName = firstMidName };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FullName_EmptyLastName_ReturnsCommaFirstName()
    {
        // Arrange
        var student = new Student { LastName = "", FirstMidName = "Alice" };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual(", Alice", result);
    }

    [TestMethod]
    public void FullName_EmptyFirstMidName_ReturnsLastNameComma()
    {
        // Arrange
        var student = new Student { LastName = "Johnson", FirstMidName = "" };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual("Johnson, ", result);
    }

    [TestMethod]
    public void FullName_BothEmpty_ReturnsCommaSpace()
    {
        // Arrange
        var student = new Student { LastName = "", FirstMidName = "" };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual(", ", result);
    }

    // --- Person properties ---

    [TestMethod]
    public void Person_ID_CanSetAndGet()
    {
