using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    // --- Constructor tests ---

    [TestMethod]
    public void Constructor_ValidInputs_SetsPageIndex()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, count: 10, pageIndex: 2, pageSize: 3);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_ValidInputs_CalculatesTotalPages()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, count: 10, pageIndex: 1, pageSize: 3);

        // Assert
        Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
    }

    [TestMethod]
    public void Constructor_ExactDivision_CalculatesTotalPagesCorrectly()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, count: 9, pageIndex: 1, pageSize: 3);

        // Assert
        Assert.AreEqual(3, list.TotalPages); // 9/3 = 3
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, count: 10, pageIndex: 1, pageSize: 3);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("a", list[0]);
        Assert.AreEqual("b", list[1]);
        Assert.AreEqual("c", list[2]);
    }

    [TestMethod]
    public void Constructor_EmptyItems_CreatesEmptyList()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), count: 0, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(0, list.Count);
        Assert.AreEqual(0, list.TotalPages);
    }

    // --- HasPreviousPage tests ---

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int> { 1 }, count: 10, pageIndex: 1, pageSize: 3);

        // Act & Assert
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int> { 4, 5, 6 }, count: 10, pageIndex: 2, pageSize: 3);

        // Act & Assert
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_LastPage_ReturnsTrue()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int> { 10 }, count: 10, pageIndex: 4, pageSize: 3);

        // Act & Assert
        Assert.IsTrue(list.HasPreviousPage);
    }

    // --- HasNextPage tests ---

    [TestMethod]
    public void HasNextPage_FirstPageOfMany_ReturnsTrue()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, count: 10, pageIndex: 1, pageSize: 3);

        // Act & Assert
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int> { 10 }, count: 10, pageIndex: 4, pageSize: 3);

        // Act & Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int> { 1, 2 }, count: 2, pageIndex: 1, pageSize: 5);

        // Act & Assert
        Assert.IsFalse(list.HasNextPage);
    }

    // --- Create tests ---

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
    }

    [TestMethod]
    public void Create_MiddlePage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 13).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 5);

        // Assert
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(13, result[2]);
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = new List<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.AreEqual(1, result.PageIndex);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_SingleItemSinglePage_CorrectProperties()
    {
        // Arrange
        var source = new List<string> { "only" }.AsQueryable();

        // Act
        var result = PaginatedList<string>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual("only", result[0]);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_PageSizeEqualsCount_SinglePage()
    {
        // Arrange
        var source = Enumerable.Range(1, 5).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service;

    [TestInitialize]
    public void TestInitialize()
    {
        _service = new NotificationService();

        // Drain the static shared queue to isolate tests
        while (_service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _service.Dispose();
    }

    // --- SendNotification (3-param overload) ---

    [TestMethod]
    public void SendNotification_ThreeParamOverload_EnqueuesNotification()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_NoUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithUserName_SetsCreatedBy()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", EntityOperation.UPDATE, "admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("admin", notification.CreatedBy);
    }

    // --- SendNotification (5-param overload with display name) ---

    [TestMethod]
    public void SendNotification_WithDisplayName_IncludesDisplayNameInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student 'John Smith' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "42", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NullDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "42", null, EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    // --- GenerateMessage (tested via SendNotification) ---

    [TestMethod]
    public void SendNotification_CreateOperation_MessageSaysCreated()
    {
        // Arrange & Act
        _service.SendNotification("Course", "101", "Biology", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("New Course 'Biology' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_MessageSaysUpdated()
    {
        // Arrange & Act
        _service.SendNotification("Course", "101", "Biology", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Course 'Biology' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_MessageSaysDeleted()
    {
        // Arrange & Act
        _service.SendNotification("Course", "101", "Biology", EntityOperation.DELETE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Course 'Biology' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_CreateWithoutDisplayName_MessageIncludesId()
    {
        // Arrange & Act
        _service.SendNotification("Department", "5", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("New Department (ID: 5) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateWithoutDisplayName_MessageIncludesId()
    {
        // Arrange & Act
        _service.SendNotification("Department", "5", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Department (ID: 5) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteWithoutDisplayName_MessageIncludesId()
    {
        // Arrange & Act
        _service.SendNotification("Department", "5", EntityOperation.DELETE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Department (ID: 5) has been deleted", notification.Message);
    }

    // --- Notification properties ---

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        var after = DateTime.Now.AddSeconds(1);
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
            $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
    }

    // --- ReceiveNotification ---

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleItems_ReturnsFifoOrder()
    {
        // Arrange
        _service.SendNotification("A", "1", EntityOperation.CREATE);
        _service.SendNotification("B", "2", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", EntityOperation.DELETE);

        // Act & Assert
        var first = _service.ReceiveNotification();
        Assert.AreEqual("A", first.EntityType);

        var second = _service.ReceiveNotification();
        Assert.AreEqual("B", second.EntityType);

        var third = _service.ReceiveNotification();
        Assert.AreEqual("C", third.EntityType);

        var fourth = _service.ReceiveNotification();
        Assert.IsNull(fourth);
    }

    // --- MarkAsRead ---

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert (no-op, should not throw)
        _service.MarkAsRead(1);
        _service.MarkAsRead(0);
        _service.MarkAsRead(-1);
    }

    // --- Dispose ---

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        _service.Dispose();
    }

    [TestMethod]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        // Act & Assert
        _service.Dispose();
        _service.Dispose();
    }

    // --- WithUserName on 5-param overload ---

    [TestMethod]
    public void SendNotification_FiveParamWithUserName_SetsCreatedBy()
    {
        // Arrange & Act
        _service.SendNotification("Course", "10", "Physics", EntityOperation.CREATE, "teacher1");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("teacher1", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_FiveParamNoUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _service.SendNotification("Course", "10", "Physics", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    // --- Empty/whitespace display name ---

    [TestMethod]
    public void SendNotification_EmptyDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "7", "", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Student (ID: 7) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WhitespaceDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "7", "   ", EntityOperation.DELETE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Student (ID: 7) has been deleted", notification.Message);
    }
}

