using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private static SchoolContext CreateContext(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Helper to drain the static NotificationService queue before each test.
    /// </summary>
    private static void DrainNotificationQueue()
    {
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    [TestInitialize]
    public void TestInitialize()
    {
        DrainNotificationQueue();
    }

    // --- Index ---

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_ReturnsViewResult));
        var controller = new NotificationsController(context);

        // Act
        var result = controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    // --- GetNotifications ---

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Arrange
        using var context = CreateContext(nameof(GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList));
        var controller = new NotificationsController(context);

        // Act
        var result = controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);

        // Use reflection to read anonymous type properties
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, (bool)successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, (int)countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsAll()
    {
        // Arrange
        using var context = CreateContext(nameof(GetNotifications_WithNotifications_ReturnsAll));
        var svc = new NotificationService();
        svc.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);
        svc.SendNotification("Course", "101", "Math", EntityOperation.UPDATE);

        var controller = new NotificationsController(context);

        // Act
        var result = controller.GetNotifications();

        // Assert
        var value = result.Value;
        Assert.IsNotNull(value);

        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, (bool)successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(2, (int)countProp.GetValue(value));

        var notifProp = value.GetType().GetProperty("notifications");
        var notifications = notifProp.GetValue(value) as List<Notification>;
        Assert.IsNotNull(notifications);
        Assert.AreEqual(2, notifications.Count);
        Assert.AreEqual("Student", notifications[0].EntityType);
        Assert.AreEqual("Course", notifications[1].EntityType);
    }

    [TestMethod]
    public void GetNotifications_MoreThanTen_LimitsToTen()
    {
        // Arrange
        using var context = CreateContext(nameof(GetNotifications_MoreThanTen_LimitsToTen));
        var svc = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        var controller = new NotificationsController(context);

        // Act
        var result = controller.GetNotifications();

        // Assert
        var value = result.Value;
        Assert.IsNotNull(value);

        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, (int)countProp.GetValue(value));

        var notifProp = value.GetType().GetProperty("notifications");
        var notifications = notifProp.GetValue(value) as List<Notification>;
        Assert.IsNotNull(notifications);
        Assert.AreEqual(10, notifications.Count);
    }

    [TestMethod]
    public void GetNotifications_DrainsQueueItems()
    {
        // Arrange - put 3 items in queue
        using var context = CreateContext(nameof(GetNotifications_DrainsQueueItems));
        var svc = new NotificationService();
        svc.SendNotification("A", "1", EntityOperation.CREATE);
        svc.SendNotification("B", "2", EntityOperation.UPDATE);
        svc.SendNotification("C", "3", EntityOperation.DELETE);

        var controller = new NotificationsController(context);

        // Act - first call drains the queue
        controller.GetNotifications();

        // Second call should return empty
        var result2 = controller.GetNotifications();
        var value2 = result2.Value;
        var countProp = value2.GetType().GetProperty("count");
        Assert.AreEqual(0, (int)countProp.GetValue(value2));
    }

    // --- MarkAsRead ---

    [TestMethod]
    public void MarkAsRead_ValidId_ReturnsSuccess()
    {
        // Arrange
        using var context = CreateContext(nameof(MarkAsRead_ValidId_ReturnsSuccess));
        var controller = new NotificationsController(context);

        // Act
        var result = controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);

        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, (bool)successProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_ZeroId_ReturnsSuccess()
    {
        // Arrange
        using var context = CreateContext(nameof(MarkAsRead_ZeroId_ReturnsSuccess));
        var controller = new NotificationsController(context);

        // Act
        var result = controller.MarkAsRead(0);

        // Assert
        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, (bool)successProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_NegativeId_ReturnsSuccess()
    {
        // Arrange
        using var context = CreateContext(nameof(MarkAsRead_NegativeId_ReturnsSuccess));
        var controller = new NotificationsController(context);

        // Act
        var result = controller.MarkAsRead(-1);

        // Assert
        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, (bool)successProp.GetValue(value));
    }
}

