using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class StudentsControllerTests
{
    private static SchoolContext CreateContext(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    private static void DrainNotificationQueue()
    {
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    private static StudentsController CreateController(SchoolContext context)
    {
        var controller = new StudentsController(context);
        // Set up TempData so DeleteConfirmed doesn't throw
        controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(), Mock.Of<ITempDataProvider>());
        return controller;
    }

    [TestInitialize]
    public void TestInitialize()
    {
        DrainNotificationQueue();
    }

    // ---- Index: default sort ----

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_DefaultSort_OrdersByLastNameAscending));
        context.Students.AddRange(
            new Student { LastName = "Zane", FirstMidName = "A", EnrollmentDate = DateTime.Today },
            new Student { LastName = "Adams", FirstMidName = "B", EnrollmentDate = DateTime.Today },
            new Student { LastName = "Miller", FirstMidName = "C", EnrollmentDate = DateTime.Today });
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null, null, null);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
        var viewResult = (ViewResult)result;
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        Assert.AreEqual("Adams", model[0].LastName);
        Assert.AreEqual("Miller", model[1].LastName);
        Assert.AreEqual("Zane", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_NameDescSort_OrdersByLastNameDescending));
        context.Students.AddRange(
            new Student { LastName = "Adams", FirstMidName = "A", EnrollmentDate = DateTime.Today },
            new Student { LastName = "Zane", FirstMidName = "B", EnrollmentDate = DateTime.Today });
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act
        var result = controller.Index("name_desc", null, null, null);

        // Assert
        var model = ((ViewResult)result).Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Zane", model[0].LastName);
        Assert.AreEqual("Adams", model[1].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_DateSort_OrdersByEnrollmentDateAscending));
        context.Students.AddRange(
            new Student { LastName = "Late", FirstMidName = "A", EnrollmentDate = new DateTime(2024, 6, 1) },
            new Student { LastName = "Early", FirstMidName = "B", EnrollmentDate = new DateTime(2020, 1, 1) });
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act
        var result = controller.Index("Date", null, null, null);

        // Assert
        var model = ((ViewResult)result).Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Early", model[0].LastName);
        Assert.AreEqual("Late", model[1].LastName);
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_DateDescSort_OrdersByEnrollmentDateDescending));
        context.Students.AddRange(
            new Student { LastName = "Early", FirstMidName = "A", EnrollmentDate = new DateTime(2020, 1, 1) },
            new Student { LastName = "Late", FirstMidName = "B", EnrollmentDate = new DateTime(2024, 6, 1) });
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act
        var result = controller.Index("date_desc", null, null, null);

        // Assert
        var model = ((ViewResult)result).Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Late", model[0].LastName);
        Assert.AreEqual("Early", model[1].LastName);
    }

    // ---- Index: search ----

    [TestMethod]
    public void Index_SearchByLastName_FiltersCorrectly()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_SearchByLastName_FiltersCorrectly));
        context.Students.AddRange(
            new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = DateTime.Today },
            new Student { LastName = "Jones", FirstMidName = "Jane", EnrollmentDate = DateTime.Today });
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null, "Smith", null);

        // Assert
        var model = ((ViewResult)result).Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Smith", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersCorrectly()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_SearchByFirstName_FiltersCorrectly));
        context.Students.AddRange(
            new Student { LastName = "A", FirstMidName = "Alice", EnrollmentDate = DateTime.Today },
            new Student { LastName = "B", FirstMidName = "Bob", EnrollmentDate = DateTime.Today });
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null, "Alice", null);

        // Assert
        var model = ((ViewResult)result).Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alice", model[0].FirstMidName);
    }

    [TestMethod]
    public void Index_SearchStringResetsPageToOne()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_SearchStringResetsPageToOne));
        context.Students.Add(new Student { LastName = "Test", FirstMidName = "User", EnrollmentDate = DateTime.Today });
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act - pass searchString (non-null) and page=5; searchString should reset page to 1
        var result = controller.Index(null, null, "Test", 5);

        // Assert - ViewBag.CurrentFilter is set
        var viewResult = (ViewResult)result;
        Assert.AreEqual("Test", controller.ViewBag.CurrentFilter);
    }

    [TestMethod]
    public void Index_NoSearchString_UsesCurrentFilter()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_NoSearchString_UsesCurrentFilter));
        context.Students.Add(new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = DateTime.Today });
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act - searchString=null, currentFilter="Smith"
        var result = controller.Index(null, "Smith", null, null);

        // Assert
        Assert.AreEqual("Smith", controller.ViewBag.CurrentFilter);
        var model = ((ViewResult)result).Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_SetsViewBagSortParameters));
        using var controller = CreateController(context);

        // Act - default (null) sortOrder
        controller.Index(null, null, null, null);

        // Assert
        Assert.AreEqual("name_desc", controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_SortDate_SetsDateSortParmToDateDesc()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_SortDate_SetsDateSortParmToDateDesc));
        using var controller = CreateController(context);

        // Act
        controller.Index("Date", null, null, null);

        // Assert
        Assert.AreEqual("date_desc", controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyPaginatedList()
    {
        // Arrange
        using var context = CreateContext(nameof(Index_EmptyDatabase_ReturnsEmptyPaginatedList));
        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null, null, null);

        // Assert
        var model = ((ViewResult)result).Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    // ---- Details ----

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateContext(nameof(Details_NullId_ReturnsBadRequest));
        using var controller = CreateController(context);

        // Act
        var result = controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        using var context = CreateContext(nameof(Details_ValidId_ReturnsViewWithStudent));
        var student = new Student { LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = DateTime.Today };
        context.Students.Add(student);
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act
        var result = controller.Details(student.ID);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
        var model = ((ViewResult)result).Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Doe", model.LastName);
        Assert.AreEqual("Jane", model.FirstMidName);
    }

    // ---- Create GET ----

    [TestMethod]
    public void CreateGet_ReturnsViewWithDefaultEnrollmentDate()
    {
        // Arrange
        using var context = CreateContext(nameof(CreateGet_ReturnsViewWithDefaultEnrollmentDate));
        using var controller = CreateController(context);

        // Act
        var result = controller.Create();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
        var model = ((ViewResult)result).Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    // ---- Create POST ----

    [TestMethod]
    public void CreatePost_ValidModel_AddsStudentAndRedirects()
    {
        // Arrange
        using var context = CreateContext(nameof(CreatePost_ValidModel_AddsStudentAndRedirects));
        using var controller = CreateController(context);

        var student = new Student
        {
            LastName = "TestStudent",
            FirstMidName = "Create",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };

        // Act
        var result = controller.Create(student);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        Assert.AreEqual(1, context.Students.Count());
        Assert.AreEqual("TestStudent", context.Students.First().LastName);
    }

    [TestMethod]
    public void CreatePost_MinValueDate_AddsModelError()
    {
        // Arrange
        using var context = CreateContext(nameof(CreatePost_MinValueDate_AddsModelError));
        using var controller = CreateController(context);

        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Min",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = controller.Create(student);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
        Assert.IsFalse(controller.ModelState.IsValid);
        Assert.IsTrue(controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void CreatePost_InvalidModel_ReturnsView()
    {
        // Arrange
        using var context = CreateContext(nameof(CreatePost_InvalidModel_ReturnsView));
        using var controller = CreateController(context);
        controller.ModelState.AddModelError("LastName", "Required");

        var student = new Student
        {
            FirstMidName = "NoLast",
            EnrollmentDate = new DateTime(2024, 1, 1)
        };

        // Act
        var result = controller.Create(student);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
        Assert.AreEqual(student, ((ViewResult)result).Model);
    }

    // ---- Edit GET ----

    [TestMethod]
    public void EditGet_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateContext(nameof(EditGet_NullId_ReturnsBadRequest));
        using var controller = CreateController(context);

        // Act
        var result = controller.Edit((int?)null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void EditGet_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        using var context = CreateContext(nameof(EditGet_ValidId_ReturnsViewWithStudent));
        var student = new Student { LastName = "Edit", FirstMidName = "Test", EnrollmentDate = DateTime.Today };
        context.Students.Add(student);
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act
        var result = controller.Edit(student.ID);

        // Assert
