        using var context = CreateContext(nameof(Initialize_DepartmentsHaveAdministrators));

        // Act
        DbInitializer.Initialize(context);

        // Assert - every department should have an InstructorID assigned
        var departments = context.Departments.ToList();
        Assert.IsTrue(departments.All(d => d.InstructorID != null));
    }
